<?php require_once dirname(__DIR__, 2).'/functions.php'; $settings=$settings ?? ($block['settings'] ?? []); ?>
<?php $posts=omh_block_posts($settings,5); ?><section class="omh-hero-slider" data-omh-slider><?php if($posts): foreach($posts as $i=>$p): ?><article class="omh-hero-slide <?=$i===0?'is-active':''?>" data-slide="<?=$i?>"><a href="<?=omh_e(omh_post_url($p))?>"><img src="<?=omh_e(omh_img($p))?>" alt="<?=omh_e($p['title'])?>"><div class="omh-hero-overlay"><span class="omh-badge"><?=omh_e($p['category_name'] ?? ($settings['title'] ?? 'GÜNDEM'))?></span><h1><?=omh_e($p['title'])?></h1><p><?=omh_e(omh_date($p))?> • 5 dk okuma</p></div></a></article><?php endforeach; ?><div class="omh-slider-numbers"><?php foreach($posts as $i=>$p): ?><button type="button" class="<?=$i===0?'is-active':''?>" data-goto="<?=$i?>"><?=str_pad((string)($i+1),2,'0',STR_PAD_LEFT)?></button><?php endforeach; ?></div><?php else: ?><div class="omh-empty">Manşet için haber bulunamadı.</div><?php endif; ?></section>
